const t=t=>{const e=(t=>{try{if(!t)return null;const e=new Date(t);return isNaN(e.getTime())?null:e}catch(e){return null}})(t);if(!e)return"时间错误";const r=new Date,n=r.getTime()-e.getTime();if(n<6e4)return"刚刚";if(n<36e5){return`${Math.floor(n/6e4)}分钟前`}if(n<864e5){return`${Math.floor(n/36e5)}小时前`}if(n<6048e5){return`${Math.floor(n/864e5)}天前`}const a=e.getFullYear(),u=String(e.getMonth()+1).padStart(2,"0"),l=String(e.getDate()).padStart(2,"0");return a===r.getFullYear()?`${u}-${l}`:`${a}-${u}-${l}`};export{t as f};
